import{_ as n,c as r,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Plattformfunktionen: Plan- und Codeüberprüfung | Plannotator","description":"Lernen Sie die Plattformfunktionen von Plannotator kennen, einschließlich Planüberprüfung und Codeüberprüfung. Beherrschen Sie visuelle Überprüfung, Kommentare hinzufügen, Bildmarkierungen und weitere Kernkompetenzen.","frontmatter":{"title":"Plattformfunktionen: Plan- und Codeüberprüfung | Plannotator","sidebarTitle":"KI-Pläne und -Codes überprüfen","subtitle":"Plattformfunktionen: Plan- und Codeüberprüfung","description":"Lernen Sie die Plattformfunktionen von Plannotator kennen, einschließlich Planüberprüfung und Codeüberprüfung. Beherrschen Sie visuelle Überprüfung, Kommentare hinzufügen, Bildmarkierungen und weitere Kernkompetenzen.","order":2},"headers":[],"relativePath":"de/backnotprop/plannotator/platforms/index.md","filePath":"de/backnotprop/plannotator/platforms/index.md"}'),i={name:"de/backnotprop/plannotator/platforms/index.md"};function o(l,e,d,s,u,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="plattformfunktionen" tabindex="-1">Plattformfunktionen <a class="header-anchor" href="#plattformfunktionen" aria-label="Permalink to &quot;Plattformfunktionen&quot;">​</a></h1><p>Dieser Abschnitt stellt die beiden Hauptfunktionen von Plannotator vor: <strong>Planüberprüfung</strong> und <strong>Codeüberprüfung</strong>. Sie lernen, wie Sie KI-generierte Pläne visuell überprüfen, verschiedene Arten von Kommentaren hinzufügen, Bildmarkierungen anhängen und Git-Diff-Codeänderungen überprüfen können.</p><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Bevor Sie beginnen</p><p>Stellen Sie sicher, dass Sie die folgenden Vorbereitungen abgeschlossen haben, bevor Sie mit diesem Abschnitt fortfahren:</p><ul><li>✅ <a href="./../start/getting-started/">Schnellstart</a> Tutorial abgeschlossen</li><li>✅ Plannotator-Plugin installiert (<a href="./../start/installation-claude-code/">Claude Code</a> oder <a href="./../start/installation-opencode/">OpenCode</a>)</li></ul></div><h2 id="kapitelinhalt" tabindex="-1">Kapitelinhalt <a class="header-anchor" href="#kapitelinhalt" aria-label="Permalink to &quot;Kapitelinhalt&quot;">​</a></h2><h3 id="planuberprufung" tabindex="-1">Planüberprüfung <a class="header-anchor" href="#planuberprufung" aria-label="Permalink to &quot;Planüberprüfung&quot;">​</a></h3><p>Lernen Sie, wie Sie KI-generierte Ausführungspläne überprüfen, Änderungsvorschläge hinzufügen und die KI nach Ihren Absichten arbeiten lassen.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">Planüberprüfung-Grundlagen</a></td><td>Lernen Sie, Plannotator zu verwenden, um KI-generierte Pläne visuell zu überprüfen, einschließlich Genehmigen oder Ablehnen von Plänen</td></tr><tr><td><a href="./plan-review-annotations/">Plankommentare hinzufügen</a></td><td>Meistern Sie das Hinzufügen verschiedener Arten von Kommentaren zu Plänen (Löschen, Ersetzen, Einfügen, Kommentieren)</td></tr><tr><td><a href="./plan-review-images/">Bildmarkierungen hinzufügen</a></td><td>Lernen Sie, Bilder an Planüberprüfungen anzuhängen und Stift-, Pfeil- und Kreistools für Markierungen zu verwenden</td></tr></tbody></table><h3 id="codeuberprufung" tabindex="-1">Codeüberprüfung <a class="header-anchor" href="#codeuberprufung" aria-label="Permalink to &quot;Codeüberprüfung&quot;">​</a></h3><p>Lernen Sie, wie Sie Codeänderungen überprüfen, zeilenbasierte Kommentare hinzufügen und Probleme vor dem Committen erkennen.</p><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./code-review-annotations/">Codekommentare hinzufügen</a></td><td>Meistern Sie das Hinzufügen zeilenbasierter Kommentare in Codeüberprüfungen (Kommentar/Vorschlag/Bedenken)</td></tr><tr><td><a href="./code-review-diff-types/">Diff-Ansicht wechseln</a></td><td>Lernen Sie, zwischen verschiedenen Diff-Typen in Codeüberprüfungen zu wechseln (nicht committet/staged/letzter Commit/Branch)</td></tr></tbody></table><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Empfohlene Lernreihenfolge</p><p>Wählen Sie den passenden Lernpfad basierend auf Ihrem Anwendungsszenario:</p><p><strong>Pfad A: Planüberprüfung priorisieren</strong> (Empfohlen für Einsteiger)</p><ol><li><a href="./plan-review-basics/">Planüberprüfung-Grundlagen</a> → Lernen Sie zuerst den grundlegenden Planüberprüfungsprozess</li><li><a href="./plan-review-annotations/">Plankommentare hinzufügen</a> → Lernen Sie, wie Sie Pläne präzise ändern</li><li><a href="./plan-review-images/">Bildmarkierungen hinzufügen</a> → Drücken Sie Ihre Absichten mit Bildern klarer aus</li><li>Danach lernen Sie die Codeüberprüfungsreihe</li></ol><p><strong>Pfad B: Codeüberprüfung priorisieren</strong> (Geeignet für Entwickler mit Codeüberprüfungserfahrung)</p><ol><li><a href="./code-review-basics/">Codeüberprüfung-Grundlagen</a> → Machen Sie sich mit der Codeüberprüfungsoberfläche vertraut</li><li><a href="./code-review-annotations/">Codekommentare hinzufügen</a> → Lernen Sie zeilenbasierte Kommentare</li><li><a href="./code-review-diff-types/">Diff-Ansicht wechseln</a> → Meistern Sie verschiedene Diff-Typen</li><li>Danach lernen Sie die Planüberprüfungsreihe</li></ol></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Abschnitts können Sie weiterlernen:</p><ul><li><a href="./../advanced/url-sharing/">URL-Freigabe</a> – Teilen Sie Pläne und Kommentare per URL für die Zusammenarbeit im Team</li><li><a href="./../advanced/obsidian-integration/">Obsidian-Integration</a> – Speichern Sie genehmigte Pläne automatisch in Obsidian</li><li><a href="./../advanced/remote-mode/">Remote-Modus</a> – Verwenden Sie Plannotator in SSH-, Devcontainer- und WSL-Umgebungen</li></ul>',16)])])}const c=n(i,[["render",o]]);export{p as __pageData,c as default};
